python - <<'PY'
import os, json, pathlib, datetime
root='.'
dirs=[f'day{d}' for d in range(16,21)]
files=[]
for d in dirs:
    if not os.path.isdir(d):
        continue
    for p in sorted(pathlib.Path(d).glob('*')):
        if p.is_file():
            st=p.stat()
            files.append((str(p), st.st_mtime, st.st_size))
# build entries
entries=[]
for path, mtime, size in files:
    bak_path = path + '.bak'
    entries.append({
        'path': path,
        'type': 'backup' if path.endswith('.bak') else 'file',
        'size_bytes': size,
        'modified_at': datetime.datetime.fromtimestamp(mtime, tz=datetime.timezone.utc).isoformat().replace('+00:00','Z'),
        'bak': {
            'exists': (not path.endswith('.bak')) and os.path.exists(bak_path),
            'path': bak_path if (not path.endswith('.bak')) and os.path.exists(bak_path) else None
        }
    })
# sort by path
entries.sort(key=lambda x:x['path'])
out={
  'week': {
    'label': 'Sprint 9 Week 1',
    'date_range': {'start':'2026-04-06','end':'2026-04-10'},
    'source_directories': [d for d in dirs if os.path.isdir(d)]
  },
  'generated_at': '2026-04-10T17:00:00+08:00',
  'scope_notes': [
    'Index lists files present under day16/..day20/ in this workspace snapshot.',
    'modified_at timestamps are from the current filesystem (UTC); use git history for authoritative business dates.',
    'bak.exists is true when a sibling file named <original>.bak exists.'
  ],
  'files': entries
}
print(json.dumps(out, indent=2, ensure_ascii=False))
PY

